// ============================================================
// LAW 3 — OPERATOR LAW
// ============================================================
const OPERATORS = {
  what: "DEFINE", who: "PERSON", where: "LOCATION",
  when: "TIME", how: "PROCESS", why: "REASON",
  explain: "EXPLAIN", describe: "DESCRIBE",
  compare: "COMPARE", define: "DEFINE",
  calculate: "MATH", solve: "MATH", compute: "MATH",
  would: "HYPOTHETICAL", could: "HYPOTHETICAL",
  should: "ADVICE", tell: "EXPLAIN",
};

function detectOperator(words) {
  for (const w of words) {
    const op = OPERATORS[w.toLowerCase()];
    if (op) return { word: w.toLowerCase(), action: op };
  }
  return { word: "unknown", action: "GENERAL" };
}

// ============================================================
// LAW 4 — MATH ENGINE
// ============================================================
function tryMath(q) {
  const clean = q.toLowerCase()
    .replace(/what is|calculate|solve|compute|find|equals/gi, "")
    .replace(/×/g,"*").replace(/÷/g,"/")
    .replace(/squared/g,"**2").replace(/cubed/g,"**3")
    .replace(/square root of\s*/g,"Math.sqrt(")
    .replace(/\bpi\b/g,"Math.PI")
    .replace(/(\d+\.?\d*)\s*%\s*of\s*(\d+\.?\d*)/g,"($1/100)*$2")
    .trim();
  if (!/[\d]/.test(clean)) return null;
  if (!/[\+\-\*\/\^%]/.test(clean) && !/Math\./.test(clean)) return null;
  try {
    // eslint-disable-next-line no-new-func
    const r = Function('"use strict"; return (' + clean + ')')();
    if (typeof r === "number" && isFinite(r))
      return Number.isInteger(r) ? r.toString() : r.toFixed(6).replace(/\.?0+$/,"");
  } catch {}
  return null;
}

function tryScenarioMath(q) {
  const text = q.toLowerCase();
  const wordNums = {one:1,two:2,three:3,four:4,five:5,six:6,seven:7,
    eight:8,nine:9,ten:10,eleven:11,twelve:12,thirteen:13,fourteen:14,
    fifteen:15,sixteen:16,seventeen:17,eighteen:18,nineteen:19,twenty:20,
    thirty:30,forty:40,fifty:50,sixty:60,seventy:70,eighty:80,ninety:90,
    hundred:100,thousand:1000,million:1000000};
  let processed = text;
  for (const [w,v] of Object.entries(wordNums)) {
    processed = processed.replace(new RegExp(`\\b${w}\\b`,'g'), ` ${v} `);
  }
  const numMatches = processed.match(/\d+(\.\d+)?/g);
  if (!numMatches || numMatches.length < 2) return null;
  const nums = numMatches.map(Number);
  const steps = [];

  // MULTI-STEP: fees × students then % deduction
  const hasFees = /fee|pay|cost|price|charge|tuition|salary|salari/i.test(text);
  const hasPct = /percent|%/i.test(text);

  if (hasFees && hasPct && nums.length >= 3) {
    const studentMatch = processed.match(/(\d+)\s*students/);
    // Find the SPENDING percentage (near salary/spend/cost keywords)
    // Not the first percentage which might be about boys/girls
    const spendPctMatch = processed.match(/(\d+)\s*percent[^.]*(?:salary|salari|spend|cost|expens)/i) ||
                          processed.match(/(?:salary|salari|spend|cost|expens)[^.]*?(\d+)\s*percent/i);
    const allPctMatches = [...processed.matchAll(/(\d+)\s*percent/gi)];
    let qty = studentMatch ? parseFloat(studentMatch[1]) : nums[0];
    // Use the LAST percentage if multiple (usually the spending one)
    let pct = spendPctMatch 
      ? parseFloat(spendPctMatch[1] || spendPctMatch[2])
      : allPctMatches.length > 1 
        ? parseFloat(allPctMatches[allPctMatches.length-1][1])
        : allPctMatches.length === 1 ? parseFloat(allPctMatches[0][1]) : null;
    let price = nums.find(n => n > qty && n !== pct);
    if (qty && price && pct) {
      const total = qty * price;
      steps.push(`Step 1: Total fees = ${qty.toLocaleString()} × ${price.toLocaleString()} = ${total.toLocaleString()}`);
      const deduction = (pct/100) * total;
      steps.push(`Step 2: ${pct}% on salaries = ${deduction.toLocaleString()}`);
      const remaining = total - deduction;
      steps.push(`Step 3: Remaining = ${total.toLocaleString()} − ${deduction.toLocaleString()} = ${remaining.toLocaleString()}`);
      steps.push(`Answer: ${remaining.toLocaleString()} shillings`);
      return steps.join('\n');
    }
  }

  // PROFIT: revenue - cost
  if (/profit|earn|revenue|income/i.test(text) && /cost|spend|expense|paid/i.test(text)) {
    const revenue = Math.max(...nums.slice(0,3));
    const cost = Math.min(...nums.slice(0,3));
    steps.push(`Step 1: Revenue = ${revenue.toLocaleString()}`);
    steps.push(`Step 2: Cost = ${cost.toLocaleString()}`);
    steps.push(`Answer: Profit = ${(revenue-cost).toLocaleString()}`);
    return steps.join('\n');
  }

  // DISTANCE = speed × time
  if (/speed|km.?h|mph|travels/i.test(text) && /hour|time/i.test(text)) {
    const speed = nums[0], time = nums[1];
    steps.push(`Step 1: Speed = ${speed} km/h, Time = ${time} hours`);
    steps.push(`Step 2: Distance = ${speed} × ${time} = ${speed*time} km`);
    steps.push(`Answer: ${speed*time} km`);
    return steps.join('\n');
  }

  // PERCENTAGE of number
  if (hasPct && nums.length >= 2) {
    const pct = nums.find(n => n <= 100) || nums[0];
    const total = nums.find(n => n > 100) || nums[1];
    const result = (pct/100)*total;
    steps.push(`Step 1: ${pct}% of ${total.toLocaleString()}`);
    steps.push(`Step 2: = (${pct} ÷ 100) × ${total.toLocaleString()}`);
    steps.push(`Answer: ${result.toLocaleString()}`);
    return steps.join('\n');
  }

  // SPLIT equally
  if (/each|per person|split|share|divided among|divided between/i.test(text)) {
    const total = Math.max(...nums), people = Math.min(...nums);
    const each = total/people;
    steps.push(`Step 1: Total = ${total.toLocaleString()}`);
    steps.push(`Step 2: ÷ ${people} people`);
    steps.push(`Answer: ${each.toLocaleString()} each`);
    return steps.join('\n');
  }

  // SUBTRACTION — left/remain
  if (/left|remain|after (giving|selling|spending|paying|losing)|fewer/i.test(text)) {
    const result = nums[0]-nums[1];
    steps.push(`Step 1: ${nums[0].toLocaleString()} − ${nums[1].toLocaleString()}`);
    steps.push(`Answer: ${result.toLocaleString()} remaining`);
    return steps.join('\n');
  }

  // ADDITION — total
  if (/total|altogether|combined|together|both|sum/i.test(text)) {
    const result = nums[0]+nums[1];
    steps.push(`Step 1: ${nums[0].toLocaleString()} + ${nums[1].toLocaleString()}`);
    steps.push(`Answer: ${result.toLocaleString()}`);
    return steps.join('\n');
  }

  return null;
}
function detectEmotion(text) {
  const words = text.toLowerCase().split(/\s+/);
  for (const w of words) {
    const clean = w.replace(/[^a-z]/g,"");
    if (EMOTIONS[clean]) return EMOTIONS[clean];
  }
  if (/i (feel|am|m) (sad|down|bad|terrible)/i.test(text)) return EMOTIONS["sad"];
  if (/i (feel|am|m) (happy|great|amazing)/i.test(text)) return EMOTIONS["happy"];
  if (/i (don.t|dont) understand/i.test(text)) return EMOTIONS["confused"];
  return null;
}
function emotionReply(type) {
  const list = EMOTION_REPLIES[type]||EMOTION_REPLIES["clarify"];
  return list[Math.floor(Math.random()*list.length)];
}

