const WHAT_ARE_YOU_REPLIES = [
  "I'm Daisy — an AI built on 7 Processing Laws. I work like a calculator but for knowledge. No massive GPUs, no training data — just pure logic, a growing dictionary and the ability to learn from every conversation. Ask me anything.",
  "I'm Daisy. I was built using The Processing Law — 7 rules that let me process language, math, science and emotions like a calculator processes numbers. The more people talk to me, the smarter I get.",
  "My name is Daisy. I'm an AI from Uganda built on 7 laws — T Order, Word Value, Operator, Calculation, Synthesis, Fallback and Emotion. I grow smarter through every conversation without needing GPUs or massive training data.",
];

function detectConversational(text) {
  const clean = text.toLowerCase().trim().replace(/[?!.,]/g,"");
  const words = clean.split(/\s+/);
  
  // Check what they are
  if (WHAT_ARE_YOU.some(p => clean.includes(p))) {
    return WHAT_ARE_YOU_REPLIES[Math.floor(Math.random()*WHAT_ARE_YOU_REPLIES.length)];
  }
  
  // How are you
  if (HOW_ARE_YOU.some(p => clean.includes(p))) {
    return HOW_ARE_YOU_REPLIES[Math.floor(Math.random()*HOW_ARE_YOU_REPLIES.length)];
  }
  
  // Thanks
  if (THANKS.some(w => words.includes(w))) {
    return THANKS_REPLIES[Math.floor(Math.random()*THANKS_REPLIES.length)];
  }
  
  // Farewells
  if (FAREWELLS.some(w => words.includes(w))) {
    if (/night/i.test(clean)) return NIGHT_REPLIES[Math.floor(Math.random()*NIGHT_REPLIES.length)];
    return FAREWELL_REPLIES[Math.floor(Math.random()*FAREWELL_REPLIES.length)];
  }
  
  // Time based greetings
  if (/good morning|morning/i.test(clean)) {
    return MORNING_REPLIES[Math.floor(Math.random()*MORNING_REPLIES.length)];
  }
  if (/good evening|evening/i.test(clean)) {
    return EVENING_REPLIES[Math.floor(Math.random()*EVENING_REPLIES.length)];
  }
  if (/good night|goodnight/i.test(clean)) {
    return NIGHT_REPLIES[Math.floor(Math.random()*NIGHT_REPLIES.length)];
  }
  
  // General greetings
  if (GREETINGS.some(w => words[0] === w || words.includes(w))) {
    return GREETING_REPLIES[Math.floor(Math.random()*GREETING_REPLIES.length)];
  }
  
  return null;
}

// ============================================================
// SYNTHESIS ENGINE — The Core New System
// ============================================================
function extractWords(question) {
  return question.toLowerCase().replace(/[?!.,]/g,"").split(/\s+/).filter(w => w.length > 1);
}

function detectJoiners(words) {
  return words.filter(w => JOINERS[w]).map(w => ({ word: w, ...JOINERS[w] }));
}

function collectDictionaryData(words, fullDict) {
  const found = [];
  for (const w of words) {
    // Check rich dictionary first
    if (fullDict[w]) {
      found.push({ word: w, data: fullDict[w] });
    }
    // Check flat dictionary — entries may be a plain string
    // (old format) or an object with definition/what_it_does/
    // examples (new format from the ingestion crawler)
    else if (FLAT_DICT[w]) {
      const entry = FLAT_DICT[w];
      if (typeof entry === "string") {
        found.push({
          word: w,
          data: {
            definition: entry,
            what_it_does: "",
            without_it: "",
            examples: "",
            related: [],
          }
        });
      } else {
        found.push({
          word: w,
          data: {
            definition: entry.definition || "",
            what_it_does: entry.what_it_does || "",
            without_it: entry.without_it || "",
            examples: entry.examples || "",
            related: entry.related || [],
          }
        });
      }
    }
  }
  return found;
}


function lc(s){ return s ? s.charAt(0).toLowerCase() + s.slice(1) : ""; }
function capitalize(s){ return s ? s.charAt(0).toUpperCase() + s.slice(1) : ""; }

function synthesizeAnswer(question, operator, collected, joiners) {
  if (collected.length === 0) return null;

  const primary   = collected[0];
  const secondary = collected[1] || null;
  const tertiary  = collected[2] || null;
  const rest      = collected.slice(3);

  const action = operator.action;

  function def(c)     { return c?.data?.definition    || ""; }
  function does(c)    { return c?.data?.what_it_does  || ""; }
  function without(c) { return c?.data?.without_it    || ""; }
  function examples(c){ return c?.data?.examples      || ""; }

  function chainRest(nodes) {
    if (!nodes || nodes.length === 0) return "";
    return nodes.map(c => {
      const d = def(c) || does(c);
      return d ? `${c.word} (${lc(d)})` : c.word;
    }).join(", ");
  }

  const joinerTypes = new Set(joiners.map(j => j.type));

  let response = "";

  if (action === "DEFINE" || action === "EXPLAIN" || action === "DESCRIBE") {
    response = `${capitalize(primary.word)} is ${lc(def(primary))}.`;
    if (does(primary)) response += ` It ${lc(does(primary))}.`;
    if (examples(primary)) response += ` Examples include ${lc(examples(primary))}.`;
    if (secondary) {
      response += ` This connects to ${secondary.word}`;
      if (def(secondary)) response += `, which is ${lc(def(secondary))}`;
      response += ".";
    }
    if (tertiary) {
      response += ` Together with ${tertiary.word}`;
      if (def(tertiary)) response += ` — ${lc(def(tertiary))} —`;
      response += ` these concepts form a connected system.`;
    }
    if (rest.length > 0) response += ` Related to this: ${chainRest(rest)}.`;
  }

  else if (action === "PROCESS") {
    response = `${capitalize(primary.word)} works through ${lc(def(primary))}.`;
    if (does(primary)) response += ` In action, it ${lc(does(primary))}.`;
    if (secondary) {
      const link = joinerTypes.has("cause")
        ? `This is possible because ${secondary.word} ${lc(does(secondary) || def(secondary))}.`
        : `This involves ${secondary.word}, which ${lc(does(secondary) || def(secondary))}.`;
      response += ` ${link}`;
    }
    if (tertiary) response += ` Meanwhile, ${tertiary.word} ${lc(does(tertiary) || def(tertiary))}.`;
    if (examples(primary)) response += ` Seen in: ${lc(examples(primary))}.`;
  }

  else if (action === "REASON") {
    const reason = does(primary) || def(primary);
    response = `${capitalize(primary.word)} matters because it ${lc(reason)}.`;
    if (without(primary)) response += ` Without it, ${lc(without(primary))}.`;
    if (secondary) {
      response += ` This is amplified by ${secondary.word}`;
      const r2 = does(secondary) || def(secondary);
      if (r2) response += `, which ${lc(r2)}`;
      response += ".";
    }
    if (tertiary) {
      response += ` Add to that ${tertiary.word}`;
      const r3 = does(tertiary) || def(tertiary);
      if (r3) response += ` — ${lc(r3)} —`;
      response += ` and you see why this system is critical.`;
    }
  }

  else if (action === "HYPOTHETICAL") {
    const subject = collected.find(c => without(c)) || primary;
    response = `If ${subject.word} — ${lc(def(subject))} — were removed, ${lc(without(subject))}.`;
    if (does(subject)) response += ` This is because it currently ${lc(does(subject))}.`;
    const others = collected.filter(c => c !== subject);
    if (others.length >= 1) {
      const o1 = others[0];
      response += ` This would also affect ${o1.word}`;
      const o1w = without(o1) || does(o1);
      if (o1w) response += `, since ${o1.word} ${lc(o1w)}`;
      response += ".";
    }
    if (others.length >= 2) {
      const o2 = others[1];
      response += ` Even ${o2.word}`;
      const o2d = def(o2);
      if (o2d) response += ` — ${lc(o2d)} —`;
      response += ` would be disrupted as a result.`;
    }
    if (others.length >= 3) {
      response += ` The chain effect would reach ${chainRest(others.slice(2))}, collapsing the entire system.`;
    }
  }

  else if (action === "COMPARE") {
    if (secondary) {
      response = `${capitalize(primary.word)} is ${lc(def(primary))}, while ${secondary.word} is ${lc(def(secondary))}.`;
      const d1 = does(primary), d2 = does(secondary);
      if (d1 && d2) response += ` ${capitalize(primary.word)} ${lc(d1)}, whereas ${secondary.word} ${lc(d2)}.`;
      if (tertiary) {
        response += ` A third angle: ${tertiary.word} is ${lc(def(tertiary))}`;
        if (does(tertiary)) response += ` and ${lc(does(tertiary))}`;
        response += ".";
      }
    } else {
      response = `${capitalize(primary.word)} is ${lc(def(primary))}.`;
      if (does(primary)) response += ` It ${lc(does(primary))}.`;
    }
  }

  else {
    if (collected.length === 1) {
      response = `${capitalize(primary.word)} is ${lc(def(primary))}.`;
      if (does(primary)) response += ` It ${lc(does(primary))}.`;
      if (examples(primary)) response += ` For example: ${lc(examples(primary))}.`;
    } else if (collected.length === 2) {
      response = `${capitalize(primary.word)} — ${lc(def(primary))} — and ${secondary.word} — ${lc(def(secondary))} — are connected.`;
      if (does(primary)) response += ` ${capitalize(primary.word)} ${lc(does(primary))}.`;
      if (does(secondary)) response += ` At the same time, ${secondary.word} ${lc(does(secondary))}.`;
    } else {
      const core = collected.slice(0, 3);
      const extra = collected.slice(3);
      response = core.map((c, i) => {
        const d = def(c), wh = does(c);
        if (i === 0) return `${capitalize(c.word)} is ${lc(d)}${wh ? `, which means it ${lc(wh)}` : ""}`;
        if (i === 1) return `${c.word} is ${lc(d)}${wh ? ` and ${lc(wh)}` : ""}`;
        if (i === 2) return `${c.word} is ${lc(d)}`;
        return "";
      }).filter(Boolean).join("; ") + ".";
      if (extra.length > 0) response += ` Also relevant: ${chainRest(extra)}.`;
    }
  }

  // JOINER OVERLAY
  if (joinerTypes.has("cause") && secondary && action !== "PROCESS" && action !== "REASON") {
    const causeText = does(secondary) || def(secondary);
    if (causeText) response += ` This happens because ${secondary.word} ${lc(causeText)}.`;
  }
  if (joinerTypes.has("condition") && secondary) {
    const condText = def(secondary) || does(secondary);
    if (condText) response += ` Under the condition that ${secondary.word} is involved — ${lc(condText)} — the outcome changes.`;
  }
  if (joinerTypes.has("contrast") && secondary && action !== "COMPARE") {
    const contrastText = does(secondary) || def(secondary);
    if (contrastText) response += ` However, ${secondary.word} ${lc(contrastText)}.`;
  }
  if (joinerTypes.has("addition") && tertiary) {
    const addText = def(tertiary) || does(tertiary);
    if (addText) response += ` Additionally, ${tertiary.word} — ${lc(addText)}.`;
  }
  if (joinerTypes.has("result") && secondary) {
    const resultText = without(primary) || does(secondary);
    if (resultText) response += ` As a result, ${lc(resultText)}.`;
  }

  return response.trim() || null;
}


// ============================================================
// LAW 6 — AI FALLBACK (for what pure laws can't handle)
// ============================================================
async function fallbackAI(question, history) {
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 8000); // 8 second timeout
    const res = await fetch("https://api.anthropic.com/v1/messages", {
      signal: controller.signal,
      method:"POST", headers:{"Content-Type":"application/json"},
      body: JSON.stringify({
        model:"claude-sonnet-4-6", max_tokens:1000,
        system:"You are a precise AI. Answer in 2-3 clear sentences. Direct and factual. Then: KEY: <keyword> | DEFINITION: <one sentence>",
        messages:[
          ...history.slice(-6).map(m=>({role:m.role,content:m.content})),
          {role:"user",content:question}
        ]
      })
    });
    clearTimeout(timeout);
    const data = await res.json();
    const text = data.content?.[0]?.text||"";
    const lines = text.split("\n").filter(Boolean);
    const keyLine = lines.find(l=>l.startsWith("KEY:"));
    const answer = lines.filter(l=>!l.startsWith("KEY:")).join(" ").trim();
    let newEntry = null;
    if (keyLine) {
      const m = keyLine.match(/KEY:\s*(\w+)\s*\|\s*DEFINITION:\s*(.+)/);
      if (m) newEntry = {key:m[1].toLowerCase(), definition:m[2].trim()};
    }
    return {answer, newEntry, offline:false};
  } catch { return {answer:null, newEntry:null, offline:true}; }
}

// ============================================================
// STORAGE
// ============================================================
async function loadLearned() {
  try { const r = await window.storage.get("dict-v5"); return r?JSON.parse(r.value):{}; } catch { return {}; }
}
async function saveLearned(d) {
  try { await window.storage.set("dict-v5", JSON.stringify(d)); } catch {}
}

// ============================================================
// MASTER ENGINE — ALL 7 LAWS + SYNTHESIS
// ============================================================
async function processQuery(question, learnedDict, history, onNewWord) {
  const fullDict = {...DICTIONARY, ...learnedDict};
  const words = extractWords(question);
  const operator = detectOperator(words);
  const joiners = detectJoiners(words);
  const collected = collectDictionaryData(words, fullDict);
  const emotion = detectEmotion(question);

  // CONVERSATIONAL CHECK — greetings, smalltalk, personality
  const conversational = detectConversational(question);
  if (conversational) return { answer: conversational, source: "personality" };

  // LAW 4 — Math always first
  const math = tryMath(question);
  if (math) return {answer: math, source:"math"};

  const scenario = tryScenarioMath(question);
  if (scenario) return {answer: scenario, source:"scenario"};

  // SYNTHESIS ENGINE — Always tries before anything else
  // Even one word in dictionary = try to build an answer
  if (collected.length > 0) {
    const synthesized = synthesizeAnswer(question, operator, collected, joiners);
    if (synthesized) {
      const prefix = emotion ? emotionReply(emotion.r) + " — " : "";
      return {
        answer: prefix + synthesized,
        source: collected.length > 1 ? "synthesis" : "dictionary",
        emotionColor: emotion?.c || null
      };
    }
  }

  // LAW 7 — Pure emotion, no facts needed
  if (emotion && collected.length === 0) {
    return {answer: emotionReply(emotion.r), source:"emotion", emotionColor: emotion.c};
  }

  // LAW 6 — ONLY fires when truly zero dictionary match
  // This is for words that don't exist in dictionary yet
  const {answer, newEntry, offline} = await fallbackAI(question, history);
  if (offline||!answer) {
    return {
      answer: "I don't have that in my dictionary yet. I'm growing every day — ask me something I know or add it to my dictionary.",
      source:"offline"
    };
  }
  if (newEntry) {
    const updated = {
      ...learnedDict,
      [newEntry.key]: {
        definition: newEntry.definition,
        what_it_does: "",
        without_it: "",
        examples: "",
        related: [],
      }
    };
    await saveLearned(updated);
    onNewWord(updated, newEntry.key);
  }
  return {answer, source:"external", learned:newEntry};
}

